#include <stdio.h>
#include <stdlib.h>

// Node structure for the binary tree
struct Node {
    int data;
    struct Node* left;
    struct Node* right;
};

// Function to create a new node
struct Node* newNode(int data) {
    struct Node* node = (struct Node*)malloc(sizeof(struct Node));
    node->data = data;
    node->left = NULL;
    node->right = NULL;
    return node;
}

// Function to perform preorder, inorder, and postorder traversal
void traverse(struct Node* root, int* pre, int* in, int* post, int* preIndex, int* inIndex, int* postIndex) {
    if (root == NULL) return;

    pre[*preIndex] = root->data;
    (*preIndex)++;

    traverse(root->left, pre, in, post, preIndex, inIndex, postIndex);

    in[*inIndex] = root->data;
    (*inIndex)++;

    traverse(root->right, pre, in, post, preIndex, inIndex, postIndex);

    post[*postIndex] = root->data;
    (*postIndex)++;
}

int main() {
    // Create a sample binary tree
    struct Node* root = newNode(1);
    root->left = newNode(2);
    root->right = newNode(3);
    root->left->left = newNode(4);
    root->left->right = newNode(5);

    int pre[100], in[100], post[100];
    int preIndex = 0, inIndex = 0, postIndex = 0;

    traverse(root, pre, in, post, &preIndex, &inIndex, &postIndex);

    printf("Preorder traversal: ");
    for (int i = 0; i < preIndex; i++) {
        printf("%d ", pre[i]);
    }
    printf("\n");

    printf("Inorder traversal: ");
    for (int i = 0; i < inIndex; i++) {
        printf("%d ", in[i]);
    }
    printf("\n");

    printf("Postorder traversal: ");
    for (int i = 0; i < postIndex; i++) {
        printf("%d ", post[i]);
    }
    printf("\n");

    return 0;
}

